export const resources = {
  en: { translation: en },
};

for (const code of Object.keys(nav)) {
  const commonStatic = {
    Home: nav[code].home,
    Algorithms: nav[code].algorithms,
    Stories: nav[code].stories,
    'Community Events': nav[code].events,
    About: nav[code].about,
    'Share Your Story': submit[code].title,
    'Help us understand how algorithms affect people in public services.': submit[code].subtitle,
    Next: submit[code].next,
    Back: submit[code].back,
    'Submit Story': submit[code].submit,
    'Search algorithms': submit[code].algorithmSearch,
    Domain: submit[code].domain,
    City: submit[code].city,
    Name: submit[code].name,
  };
  resources[code] = {
    translation: {
      nav: nav[code],
      submit: submit[code],
      staticText: {
        ...commonStatic,
        ...(staticText[code] || {}),
        ...(genericStatic[code] || {}),
        ...(domainText[code] || {}),
        ...(code === 'zh' ? zhExtraStatic : {}),
      },
    },
  };
}
